int lengthOfLongestSubstring(char * s){
    int map[256] = {0};
    int l = 0, r = 0, mx = 0;
    while(s[r]) {
        if(map[s[r]] > 0) {
            l = (l > map[s[r]]) ? l : map[s[r]];
        }
        map[s[r]] = r + 1;
        int len = r - l + 1;
        if(len > mx) mx = len;
        r++;
    }
    return mx;
}

