        if(height[l] < height[r]) {
            if(height[l] >= lm) lm = height[l];
            else ans += lm - height[l];
            l++;
        } else {
            if(height[r] >= rm) rm = height[r];
            else ans += rm - height[r];
            r--;
        }
    }
    return ans;
}

